const msg = $input.all()[0].json.message || $input.all()[0].json;
const photo = msg.photo;
const doc = msg.document;
const chatId = msg.chat ? msg.chat.id : '';
const caption = msg.caption || msg.text || '';
const botToken = 'BURAYA_BOT_TOKEN_GIRIN';

// PDF kontrolu
if (doc && doc.mime_type === 'application/pdf') {
  const fileId = doc.file_id;
  return [{
    json: {
      hasFile: true, fileType: 'pdf', fileId, chatId, caption, botToken,
      fileName: doc.file_name || 'belge.pdf',
      getFileUrl: 'https://api.telegram.org/bot' + botToken + '/getFile?file_id=' + fileId
    }
  }];
}

// Fotograf kontrolu
if (photo && photo.length > 0) {
  const fileId = photo[photo.length - 1].file_id;
  return [{
    json: {
      hasFile: true, fileType: 'photo', fileId, chatId, caption, botToken,
      fileName: 'photo.jpg',
      getFileUrl: 'https://api.telegram.org/bot' + botToken + '/getFile?file_id=' + fileId
    }
  }];
}

return [{ json: { hasFile: false, chatId, mesaj: '📎 Lutfen bir fotograf veya PDF gonderin!\n\nDesteklenen belgeler:\n📄 Fatura / Fis\n💳 Kartvizit\n💊 Recete\n📋 Form\n📑 PDF Belge\n\nIpucu: Aciklamaya belge turunu yazin (ör: fatura)' } }];

const items = $input.all();
const binaryKey = Object.keys(items[0].binary || {})[0];

if (!binaryKey) {
  return [{ json: { error: 'Binary data bulunamadi' } }];
}

const binaryData = items[0].binary[binaryKey];
let base64Data = '';
try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
  base64Data = buffer.toString('base64');
} catch(e) {
  if (binaryData.data && binaryData.data.length > 100) {
    base64Data = binaryData.data;
  } else {
    return [{ json: { error: 'Base64 cevrimi basarisiz: ' + e.message } }];
  }
}

const fileType = $('Fotograf Bilgileri').first().json.fileType;
let mimeType = binaryData.mimeType || 'image/jpeg';

// Dosya turune gore mimeType belirle
if (fileType === 'pdf') {
  mimeType = 'application/pdf';
} else if (mimeType === 'application/octet-stream') {
  mimeType = 'image/jpeg';
}

const chatId = $('Fotograf Bilgileri').first().json.chatId;
const caption = $('Fotograf Bilgileri').first().json.caption || '';
const fileName = $('Fotograf Bilgileri').first().json.fileName || '';

let docType = 'genel';
const lower = caption.toLowerCase();
if (lower.includes('fatura') || lower.includes('fis')) docType = 'fatura';
else if (lower.includes('kartvizit') || lower.includes('card')) docType = 'kartvizit';
else if (lower.includes('recete') || lower.includes('ilac')) docType = 'recete';
else if (lower.includes('form') || lower.includes('basvuru')) docType = 'form';

let promptText = '';
if (docType === 'fatura') {
  promptText = 'Bu bir fatura veya fis belgesidir. Icerigini analiz et ve su bilgileri JSON olarak cikar: {firma_adi, tarih, toplam_tutar, kdv_tutar, kalemler: [{urun, adet, birim_fiyat, toplam}], odeme_yontemi, fatura_no}. SADECE JSON dondur.';
} else if (docType === 'kartvizit') {
  promptText = 'Bu bir kartvizit belgesidir. Icerigini analiz et ve su bilgileri JSON olarak cikar: {ad_soyad, unvan, sirket, telefon, email, adres, website}. SADECE JSON dondur.';
} else if (docType === 'recete') {
  promptText = 'Bu bir recete belgesidir. Icerigini analiz et ve su bilgileri JSON olarak cikar: {doktor_adi, hasta_adi, tarih, ilaclar: [{ilac_adi, dozaj, kullanim_sekli, sure}], tani}. SADECE JSON dondur.';
} else if (docType === 'form') {
  promptText = 'Bu bir form belgesidir. Formdaki tum alanlari ve degerlerini JSON olarak cikar: {alan_adi: deger} formatinda. SADECE JSON dondur.';
} else {
  promptText = 'Bu bir belge. Belgedeki TUM metni ve bilgileri oku. Belge turunu tespit et. Tum icerigi yapilandirilmis JSON formatinda dondur: {belge_turu, sayfa_sayisi, icerik: {anahtar: deger seklinde TUM bilgiler}, tablo_verileri: [{satir verisi}] eger tablo varsa}. SADECE JSON dondur. Hicbir bilgiyi atlama.';
}

return [{ json: { base64Data, mimeType, chatId, docType, promptText, fileType, fileName } }];

const gemini = $input.all()[0].json;
const chatId = $('Gemini Vision Hazirla').first().json.chatId;
const docType = $('Gemini Vision Hazirla').first().json.docType;
const fileType = $('Gemini Vision Hazirla').first().json.fileType;
const fileName = $('Gemini Vision Hazirla').first().json.fileName;
const tarih = new Date().toLocaleDateString('tr-TR');
const saat = new Date().toLocaleTimeString('tr-TR', { hour: '2-digit', minute: '2-digit' });

let jsonData = {};
let rawText = '';

try {
  rawText = gemini.candidates[0].content.parts[0].text;
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (jsonMatch) jsonData = JSON.parse(jsonMatch[0]);
} catch (e) {
  jsonData = { hata: 'JSON ayristirilamadi', ham_metin: rawText ? rawText.substring(0, 500) : 'Yanit alinamadi' };
}

const sheetsData = { Tarih: tarih, Saat: saat, 'Belge Turu': docType, 'Dosya Tipi': fileType.toUpperCase(), 'Dosya Adi': fileName };

function flatten(obj, prefix) {
  for (const key of Object.keys(obj)) {
    const val = obj[key];
    const newKey = prefix ? prefix + '_' + key : key;
    if (Array.isArray(val)) {
      sheetsData[newKey] = val.map(item => typeof item === 'object' ? Object.values(item).join(' | ') : String(item)).join(' /// ');
    } else if (typeof val === 'object' && val !== null) {
      flatten(val, newKey);
    } else {
      sheetsData[newKey] = String(val || '');
    }
  }
}
flatten(jsonData, '');

const icon = fileType === 'pdf' ? '📑' : '📸';
let mesaj = icon + ' BELGE BASARIYLA ISLENDI!\n📅 ' + tarih + ' ' + saat + '\n📄 Tur: ' + docType + ' | ' + fileType.toUpperCase() + '\n';
if (fileName) mesaj += '📎 Dosya: ' + fileName + '\n';
mesaj += '━━━━━━━━━━━━━━━━━━━━\n\n';

for (const key of Object.keys(jsonData)) {
  const val = jsonData[key];
  if (Array.isArray(val)) {
    mesaj += '📌 ' + key + ':\n';
    val.forEach((item, i) => { mesaj += '  ' + (i+1) + '. ' + (typeof item === 'object' ? Object.values(item).join(' | ') : item) + '\n'; });
  } else if (typeof val === 'object' && val !== null) {
    mesaj += '📌 ' + key + ': ' + JSON.stringify(val) + '\n';
  } else {
    mesaj += '📌 ' + key + ': ' + val + '\n';
  }
}
mesaj += '\n━━━━━━━━━━━━━━━━━━━━\n✅ Google Sheets kaydedildi\n🤖 Gemini Vision AI';

return [{ json: { ...sheetsData, chatId, mesaj } }];
